var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐흠, 여긴 밤바다도 참 경치가 좋군.","JPN":"ふむ、ここの海は夜景も素晴らしいな。","ENG":"Hmm, even the night view is beautiful here.","TWN":"哇，海邊的夜景好美。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"촬영해 두었다가 박 교수에게 시뮬레이션으로 구현해 달라고 해도 좋겠어.","JPN":"撮影しておいて、オリヴィエ教授にシミュレーションで再現してほしいぐらいだ。","ENG":"Maybe I should film it and send it to Professor Park to create a simulation.","TWN":"我要把它拍下來給奧利維亞教授，讓她模擬一個假的出來。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그런데 릴리 양, 자네는 계속 날 따라다닐 생각인가?","JPN":"ところでリリー、君はずっと私について来るつもりかね？","ENG":"By the way, Lily, are you planning to follow me around all the time?","TWN":"我說莉莉，你打算繼續這樣跟著我嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"네. 저는 수면 담당이니까요.","JPN":"はい。私は熟眠担当ですから。","ENG":"Of course, I’m responsible for matters related to sleep.","TWN":"是的，因為我是負責主人的睡眠。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"원하실 때라면 언제든 안락한 수면을 취하실 수 있게, 주인님의 곁을 지켜야 합니다.","JPN":"お望みの際にいつでも快適な睡眠をとることができるよう、ご主人様のそばを守る必要があります。","ENG":"I have to stay with you so that you can comfortably rest whenever you want to sleep.","TWN":"為了幫助主人可以隨時得入眠，所以必須時時跟著主人。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하. 베로니카 양만큼 투철한 직업 정신이군.","JPN":"ハハハ。ベロニカに匹敵するプロのメイドさんだな。","ENG":"Hah hah, you’re just like Veronica. Very passionate about your work.","TWN":"哈哈，你跟貝洛妮卡一樣很敬業呢！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"감사합니다. 메이드장님에 비하기에는 아직 부족하지만요.","JPN":"ありがとうございます。メイド長と比べるにはまだ未熟ではありますが。","ENG":"Thank you, but I’m still not good enough when compared to the Chief Maid.","TWN":"謝謝！但我還沒資格跟女僕長相提並論。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그보다 주인님, 곤경에 처한 마을을 도우시겠다는 뜻은 이해했습니다.","JPN":"ところでご主人様、困っている村人を助けたいという意志は理解できました。","ENG":"Master, I understand you want to help this village in trouble.","TWN":"主人，您的意思是想幫助處於困境的村莊對吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"저한테 꿀잼인 방안이 있어요. 들어 보시겠습니까?","JPN":"私にやばたにえんな方法があります。聞いてくださいませんか？","ENG":"I have one very LMAO solution. Do you care to listen?","TWN":"那我有個有趣的提議，您要聽聽嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 그래? 어떤 방안인가?","JPN":"おお、そうか？　どんな方法だ？","ENG":"Oh? What is it?","TWN":"喔，是嗎？說來聽聽！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"경계가 해이해지는 동틀 무렵에 용병들의 주둔지와 리조트로 침입하는 겁니다.","JPN":"警戒が緩む明け方に、傭兵のアジトとリゾートに侵入するのです。","ENG":"We sneak into the mercenaries’ outpost and resort at dawn when their guard is down.","TWN":"趁天快亮之前警戒正鬆懈的時候，偷襲傭兵的營地和度假村。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"주요 인사들만 <color=#ffd34c>처분</color>하면 다른 이들은 자연스럽게 서렌을 치겠죠.","JPN":"重役だけを<color=#ffd34c>処分</color>すれば、他の人は自然と身を引くでしょう。","ENG":"Then we <color=#ffd34c>terminate</color> high value targets and rest of them will go GG.","TWN":"所謂<color=#ffd34c>擒賊先擒王</color>，只要先除掉老大，其他人自然會乖乖就範。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"처분이라면……. 맨션의 해결 방식인가?","JPN":"処分ということは……マンションのやり方か。","ENG":"Terminate... Is that how the Mansion solves its problems?","TWN":"所以你的意思是…要用曼森的方式處理嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그 제안은 못 들은 걸로 하겠네.","JPN":"その提案は聞かなかったことにする。","ENG":"I’ll just pretend I didn’t hear that.","TWN":"這個提議我會當作沒聽到。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"맨션의 방식이 거슬리실 수도 있지만, 그게 마을을 돕는 가장 쉬운 길입니다.","JPN":"マンションのやり方で気が進まないかもしれませんが、それが村を助ける一番簡単な方法です。","ENG":"You might not like it, but it’s the easiest way.","TWN":"雖然曼森的方式不光彩，但這是幫助村莊最容易的方法。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"손에 피를 묻히고 끝낼 생각이었다면 진즉 그랬겠지.","JPN":"手を血に染めてまで終わらせるつもりだったら、最初からそうしただろう。","ENG":"I would have done it already if I was willing to use violence.","TWN":"如果打打殺殺就能解決問題，那我早就這麼做了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네가 말한 방식으로 해결해도 마을 사람들은 기뻐하지 않을 거야. 내가 장담하지.","JPN":"しかし、君の提案どおりにして解決しても、村人は喜ばない。私が断言する。","ENG":"I don’t think the villagers will be happy to see their troubles go away like that either. I’m sure of it.","TWN":"只是我敢保證，若是用你說的方式解決，那村裡的人也不會高興的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"But...","TWN":"可是…"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그리고 베로니카 양이 그런 쉬운 길을 택했다면, 나는 자네와 만나지 못했을 걸세.","JPN":"ベロニカがそんな簡単な道を選んでいたなら、私は君とこうして会えなかったはずだ。","ENG":"And if Veronica had chosen the easy way in the past, I wouldn't have met you.","TWN":"如果當初貝洛妮卡，也是選擇用你所謂容易的方法，那我們今天也不會站在這裡。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그리고 어쨌든 계약은 계약이지!","JPN":"そしてとにかく、契約は契約だ！","ENG":"Well, a contract is a contract!","TWN":"另外，合約就是合約！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"고객 만족도가 떨어지는 기업은 오래 살아남을 수 없는 법!","JPN":"顧客満足度が低い企業は長くは生き残れないもの！","ENG":"Clients come first, and we’re here to make them happy!","TWN":"犧牲客人滿意度的企業，是不可能長久的！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"……죄송합니다. 하마터면 제가 메이드장님의 체면을 깎을 뻔했어요.","JPN":"……申し訳ありません。危うく私がメイド長に恥をかかせるところでした。","ENG":"... My apologies. I didn’t mean to disgrace the Chief Maid.","TWN":"…抱歉！我差點丟了女僕長臉。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그럼, 내일은 어떻게 할 생각이시죠?","JPN":"では、明日はどうするつもりですか？","ENG":"Then what are you going to do tomorrow?","TWN":"那老闆明天打算怎麼做呢？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"아, 아. 여기는 릴리. 무전 감도 테스트 중입니다.","JPN":"あー、あー、こちらリリー。無線感度テスト中です。","ENG":"Hello, this is Lily. Radio test. Radio Test.","TWN":"喂，喂，我是莉莉。無線通訊測試中。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"다들 지급 받은 무전기는 잘 들리시나요?","JPN":"皆さん支給された無線機は問題なく聞こえますか？","ENG":"Everyone, do you hear me?","TWN":"剛才大家拿到的無線對講機收得到訊號嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"우와~ 이러니까 꼭 영화 속에서 나오는 스파이 같아요~","JPN":"うわあ～まるで映画の中に出てくるスパイみたいです～！","ENG":"Wow, I feel like I’m in a spy movie!","TWN":"哇～感覺好像在演間諜電影喔～"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L40_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"훗훗훗. 너무 들뜨면 곤란해, 친구. 실전에서의 방심은 죽음을 부르는 법이거든.","JPN":"フッフッフッ。浮かれては困るぞ、友よ。実戦での油断は死を招くものだ。","ENG":"Heh heh. Stay calm, my friend. Sloppiness could result in death.","TWN":"呵呵，這位朋友，請不要太興奮。在戰場上可是一不小心就會喪命的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"캬아~! 분위기 죽인다! 노이즈 섞인 내 목소리도 들어 보고 싶어!","JPN":"ふー！　最高の雰囲気だな！　ノイズ混じりの自分の声も聞いてみたいな！","ENG":"Gee, I love the atmosphere! I would love to hear my voice with all that static!","TWN":"哇～！好酷喔！真想聽聽對講機裡的雜訊！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"여기는 시그마! 대기 중입니다!","JPN":"こちらシグマ！　待機中です！","ENG":"This is Sigma standing by!","TWN":"我是西格瑪！待命中！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"모네도 따님 곁에 딱 붙어 있지 말임다, 선배님!","JPN":"モネもシグマお嬢様の隣にピッタリくっついているっす、先輩！","ENG":"Mone is here with Sigma Lady, ma’am!","TWN":"前輩，莫妮也在千金身旁唷！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"임시 현장 지휘를 맡은 릴리입니다. 잘 부탁드립니다.","JPN":"臨時現場指揮を執ったリリーです。どうぞよろしくお願いします。","ENG":"Hello, I’m Lily and I’ll be in charge today.","TWN":"我是擔任臨時指揮官的莉莉。，請多多指教。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"어젯밤 주인님의 계획을 들은 뒤, 노답 삼총사 여러분을 효율적으로 운용할 방안을 고안했습니다.","JPN":"昨夜ご主人様の計画を聞いた後、あたおか三銃士の皆様を効率的に運用する案を考案しました。","ENG":"After listening to the Master’s plan, I came up with an additional plan that can utilize the FUBAR trio more efficiently.","TWN":"昨晚聽完主人的計畫後，我規劃出一套，能夠有效利用傻呆萌三人幫的方案。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"노, 노답……","JPN":"あ、あたおか……","ENG":"F-FUBAR...","TWN":"傻…呆萌…"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"삼총사요?","JPN":"三銃士？","ENG":"... Trio?","TWN":"三人幫？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"어떤 분들인지는 몰라도 저는 아니겠네요.","JPN":"誰のことなのか知りませんが、私は違いますよ。","ENG":"I’m sure that doesn’t include me.","TWN":"哪三個人？應該不是我啦！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"점장님이 며칠 전에도 저더러 <color=#ffd34c>너 같은 애는 진짜 처음 본다</color>고 하셨거든요.","JPN":"数日前にも店長に<color=#ffd34c>お前みたいな子は見たこともない</color>と言われたんです。","ENG":"The convenience store manager told me a few days ago, <color=#ffd34c>”I’ve never seen anyone like you before.”</color>","TWN":"因為店長前幾天還誇獎我，說我真是讓他<color=#ffd34c>大開眼界</color>呢！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"후훗, 이러다 덜컥 정식 아르바이트생 되는 거 아닐까요?","JPN":"フフッ、あんなに褒められたってことは正式に雇ってもらえることになるかもです！","ENG":"I’m sure the manager will soon promote me to a real part-timer!","TWN":"嘿嘿，我會不會突然就變成正職工讀生啦？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"그건 내가 들어도 혼내려고 한 말 같아, 친구.","JPN":"それはどう考えても指摘の言葉だと思うんだが、友よ。","ENG":"I don’t think manager was complimenting you, my friend.","TWN":"這位朋友，我想那應該是在罵你的意思。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"여러분은 각자 맡은 일만 충실하게 해 주시면 돼요. 뭘 해야 하는지 간단하게 말씀드리겠습니다.","JPN":"皆様はそれぞれ任された仕事だけ集中してください。何をすべきなのか簡単に申し上げます。","ENG":"You just carry on with what you’re told to do. Here are the instructions.","TWN":"大家只要各司其職就好，接下來我會簡單地告訴大家該做什麼。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"첫째, 세리나 님과 시엔 님은 용병들의 주둔지에 감금되어 있는 여성을 구출해 주세요.","JPN":"まず、セリーナさんとシエンさんは、傭兵のアジトに監禁されている女性を救出してください。","ENG":"First, Serina and Xien will go to the mercenaries’ outpost and rescue a woman detained in the building.","TWN":"第一，瑟琳娜和西恩，請救出被關在傭兵營地的女生。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"주력이 이동 중이니 주둔지에는 몇 명 없을 겁니다. 침투로는 제가 드린 지도를 참고하세요.","JPN":"主戦力は移動中なのでアジトには数人しかいないでしょう。侵入経路は私が差し上げた地図を参考にしてください。","ENG":"The main forces will be away, so there won’t be many guarding the post. Please refer to the map I gave you for the approach route.","TWN":"主要人士都在移動中，營地應該剩沒幾個人。潛入的路線，請參考我提供的地圖。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"훗훗훗. 맡겨 둬. 해변의 질서를 지키러 나타난 이 린 시엔님께 불가능은 없으니까.","JPN":"フッフッフッ、任せてくれ。ビーチの秩序を守るために現れたリン・シエン様に不可能などない。","ENG":"Heh heh. Leave it to me. I, Lin Xien, am here to restore the order of the beach.","TWN":"呵呵呵，交給我吧！我來就是要維護海灘的秩序，包在我身上！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"와아, 이거 혹시 관광지에서 한다는 역할극 같은 건가요?","JPN":"わあ～これって観光地が舞台のロールプレイみたいなものですか？","ENG":"Hey, is this the role playing thing that tourists do?","TWN":"哇，這是在旅遊景點上演的情境劇嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"그러면 제 설정은 노점 직원으로 위장한 미모의 스파이?","JPN":"それじゃあ、私の設定は露店の店員に偽装した美貌のスパイ？","ENG":"Then I’ll be a beautiful spy disguised as a street vendor.","TWN":"那麼我的人設是僞裝成店員的美女間諜？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"정말 저 두 사람한테 맡겨도 돼? 괜히 일만 복잡해지는 거 아냐?","JPN":"本当にあの二人に任せてもいいの？　余計に状況が複雑になるだけじゃない？","ENG":"Are you sure they will be okay? What if they cause trouble?","TWN":"真的可以交給他們兩個嗎？ 事情不會變得更複雜吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"믿음은 안 가도 주인님께서 부르신 사람들입니다.","JPN":"信用はできませんが、ご主人様に呼ばれた人たちです。","ENG":"I don’t really trust them either, but the Master chose them.","TWN":"再怎麼說也是主人找來的人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"내 생각엔 그 주인님부터가 문제인 것 같은데…….","JPN":"個人的には、そもそもそのご主人様が問題だと思うけど……","ENG":"I have a feeling that the Master is also a problem...","TWN":"但我覺得那個主人本身就很有問題…"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"둘째, 마을을 지키는 일입니다.","JPN":"ふたつ目、村を守ることです。","ENG":"Second, we have to protect the village.","TWN":"第二是保護村莊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"이건 시그마 아가씨와 모네에게 부탁드리겠습니다.","JPN":"これはシグマお嬢様とモネにお任せします。","ENG":"Sigma and Mone will be on it.","TWN":"這件事就交給西格瑪小姐和莫妮。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"어? 정말? 나도 잡혀 있는 사람 도와 주러 가면 안 돼?","JPN":"え？　本当に？　私も助けに行くのはダメ？","ENG":"Huh? Really? Can’t I go and save the prisoner?","TWN":"真的喔？我不可以一起去救人嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"안 됩니다. 아가씨께선 해적 선장과의 결투를 준비하셔야죠.","JPN":"いけません。お嬢様は海賊船長との決闘にお備えください。","ENG":"You have to be here. You’ll be fighting the pirate captain.","TWN":"不可以，小姐要準備與海盜船長決鬥。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"맞다! 해적 언니! 여기 있으면 오는 거야?","JPN":"そうだ！　海賊のお姉ちゃん！　ここにいれば来てくれるの？","ENG":"Oh, the pirate lady! She’ll be here?","TWN":"對吼！那個海盜姊姊！我在這裡等她來嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"에헴! 출항 준비를 해라, 모네 선원!","JPN":"えっへん！　出航の準備だ、モネ船員！","ENG":"Ahem! Get the ship ready, sailor Mone!","TWN":"咳咳！莫妮船員，準備啟航囉！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"오늘 이 해변의 진짜 해적 선장을 가리는 거다!","JPN":"今日こそこの海で、本物の海賊船長を決めるのだ！","ENG":"Today, we’ll see who’s the real pirate captain of the sea!","TWN":"今天我就是這片海上真正的海盜船長！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"알겠슴다, 선장님!","JPN":"了解っす、船長！","ENG":"Aye aye, captain!","TWN":"遵命唷，船長！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"이걸로 안심이군요. 아가씨의 신변을 위험하게 만들 수는 없죠.","JPN":"これで安心ですね。お嬢様を危険にさらすわけにはいかないので。","ENG":"That went well. I didn’t want to put the Master’s daughter in danger.","TWN":"那我就放心了，畢竟不能將小姐置於危險之中。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"묘하게 우호적이네. 자기 입으로 지켜본다느니 어쩌느니 했으면서.","JPN":"妙に友好的じゃない。様子見するとか言ってたくせに。","ENG":"You’re being oddly friendly. Didn’t you say you were going to watch the Master? To see if he really deserves his position?","TWN":"你怎麼變得這麼友善？你不是說要盯著他嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"어젯밤에 해변에서 둘이 있을 때 최면에라도 당한 거야?","JPN":"昨夜海辺で二人きりだった時に催眠術でもかけられたの？","ENG":"What happened? The Master hypnotized you yesterday at the beach?","TWN":"昨天晚上你們在海邊時有發生什麼事嗎？你被催眠喔？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"맨션의 교육은 그렇게 허술하지 않습니다. 주인님의 숨겨진 면모를 엿봤다고 해 두죠.","JPN":"そんなものにかかるほどマンションの教育は甘くありません。ご主人様の隠された一面を見ることができたと言えば、わかるでしょうか。","ENG":"I learned well from the Mansion. Let’s just say that I recognized his hidden aspects.","TWN":"曼森的教育沒有那麼脆弱。你就當作，我發現了主人不為人知的一面吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"마지막으로 저희는 마을로 진입하려는 적들을 방해해야 합니다, 리코리스.","JPN":"最後に、私たちは村に押しよせる敵を妨害します、リコリス。","ENG":"Now, the last part of the plan. We have to stop enemies entering the village, Lycoris.","TWN":"最後，莉克麗絲，你和我要妨礙闖進村莊的敵人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"가죠. 손님들을 성대하게 대접해 드리러.","JPN":"では、開始します。招かれざる客を盛大にもてなして差し上げましょう。","ENG":"Let’s go. We have to welcome the guests.","TWN":"走吧，客人在等我們呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};